// src/lib/generateProfilePDF.js — Labtech Training
// Requires: npm install jspdf
import { jsPDF } from "jspdf";
import { UNITS } from "./units";

const C = {
  navy:[8,26,71], navyMid:[22,64,111], blue:[28,94,168],
  teal:[50,186,154], green:[22,101,52], greenBg:[240,253,244], greenBdr:[134,239,172],
  red:[201,53,53], redBg:[254,234,234], redBdr:[252,165,165],
  amber:[146,80,10], amberBg:[253,243,224], amberBdr:[245,215,138],
  purple:[109,40,217], purpBg:[237,233,254],
  gray:[107,114,128], grayLt:[243,244,246], grayBdr:[229,231,235],
  white:[255,255,255], black:[17,24,39], mid:[55,65,81], light:[107,114,128],
};

const PW=210, ML=14, CW=182, PH=297, FH=10, BTOP=14;

const box=(d,x,y,w,h,c,s="F")=>{d.setFillColor(...c);d.rect(x,y,w,h,s);};
const ln=(d,x1,y1,x2,y2,c,lw=0.2)=>{d.setLineWidth(lw);d.setDrawColor(...c);d.line(x1,y1,x2,y2);};
const t=(d,s,x,y,sz,c,bold=false,opts={})=>{
  d.setFontSize(sz);d.setFont("helvetica",bold?"bold":"normal");
  d.setTextColor(...c);d.text(String(s??""),x,y,opts);
};

function fmtDate(raw) {
  if (!raw) return "—";
  const s = String(raw).trim();
  const m = s.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (m) return `${m[3]}/${m[2]}/${m[1]}`;
  if (s.match(/^\d{2}\/\d{2}\/\d{4}/)) return s;
  return s;
}

function chk(doc, y, need, footer) {
  if (y + need > PH - FH - 6) { footer(doc); doc.addPage(); return BTOP; }
  return y;
}

function drawFooter(doc) {
  const cur = doc.internal.getCurrentPageInfo().pageNumber;
  box(doc,0,PH-FH,PW,FH,C.navy);
  t(doc,"Labtech Training  —  Trainer Competency Portal  —  Standards for RTOs 2025",ML,PH-3.5,6.5,[160,180,215]);
  t(doc,`Page ${cur}`,PW-ML,PH-3.5,6.5,[160,180,215],false,{align:"right"});
}

function secHead(doc, label, y, status) {
  box(doc,ML,y,3,8,C.teal);
  t(doc,label,ML+5,y+5.8,9.5,C.navy,true);
  if (status==="approved") {
    box(doc,ML+CW-28,y+0.5,28,7,C.greenBg); box(doc,ML+CW-28,y+0.5,28,7,C.greenBdr,"S");
    t(doc,"Approved",ML+CW-14,y+5.8,7,C.green,true,{align:"center"});
  } else if (status==="rejected") {
    box(doc,ML+CW-30,y+0.5,30,7,C.redBg); box(doc,ML+CW-30,y+0.5,30,7,C.redBdr,"S");
    t(doc,"Not Approved",ML+CW-15,y+5.8,7,C.red,true,{align:"center"});
  } else if (status==="pending") {
    box(doc,ML+CW-38,y+0.5,38,7,C.amberBg); box(doc,ML+CW-38,y+0.5,38,7,C.amberBdr,"S");
    t(doc,"Awaiting Approval",ML+CW-19,y+5.8,7,C.amber,true,{align:"center"});
  }
  ln(doc,ML,y+9,ML+CW,y+9,C.grayBdr,0.3);
  return y+13;
}

function fldAt(doc, label, value, x, y, maxW) {
  t(doc,label.toUpperCase(),x,y,5.5,C.light,true);
  const lines = doc.splitTextToSize(String(value||"—"), maxW||55);
  lines.forEach((line,i) => t(doc,line,x,y+5+i*4.5,8,C.black));
}

function hasExp(responses, unitCode) {
  return (responses||[]).some(r=>r.unit_code===unitCode&&r.response==="yes");
}

// LOGO_LINE — replaced by Python build script
const LOGO = "";

export async function generateProfilePDF({
  trainer, trainerProfile, industryQuals, evidenceFiles,
  questResponses, experienceData, assignedUnits, streams=[], streamUnits={}
}) {
  const doc = new jsPDF({orientation:"portrait",unit:"mm",format:"a4"});

  // ── COVER ──────────────────────────────────────────────────────────────────
  box(doc,0,0,PW,48,C.navy);
  box(doc,0,45,PW,3,C.teal);
  try { doc.addImage(LOGO,"JPEG",ML,5,32,32); } catch(e) {}

  t(doc,"Labtech Training",ML+38,13,8,[180,200,230]);
  t(doc,"Trainer Competency Profile",ML+38,23,15,C.white,true);
  t(doc,"Standards for RTOs 2025  |  AF3.21",ML+38,31,8,[160,185,220]);
  t(doc,trainer.full_name||"—",PW-ML,17,13,C.white,true,{align:"right"});
  t(doc,trainer.email||"",PW-ML,25,8,[180,200,230],false,{align:"right"});

  const sc=trainer.compliance_status||"Incomplete";
  let pBg=C.amberBg,pFg=C.amber;
  if(sc==="Compliant"){pBg=[210,252,231];pFg=C.green;}
  else if(sc==="Incomplete"){pBg=C.redBg;pFg=C.red;}
  else if(sc==="Under Review"){pBg=[219,234,254];pFg=C.blue;}
  box(doc,PW-ML-32,30,32,7,pBg);
  t(doc,sc,PW-ML-16,36,7,pFg,true,{align:"center"});
  t(doc,`Generated ${new Date().toLocaleDateString("en-AU",{day:"numeric",month:"long",year:"numeric"})}`,PW-ML,43.5,7,[150,175,210],false,{align:"right"});

  // Summary strip
  box(doc,0,48,PW,20,C.grayLt);
  ln(doc,0,68,PW,68,C.grayBdr);
  const qYes=(questResponses||[]).filter(r=>r.response==="yes").length;
  const qTot=(questResponses||[]).length;
  const eApp=(experienceData||[]).filter(e=>e.competency_confirmed===true).length;
  const eTot=(assignedUnits||[]).length;
  const credCode=trainerProfile?.tae_qualification?.split(" ")[0]||trainerProfile?.under_direction_qualification?.split(" ")[0]||"—";
  const sum=[
    {lbl:"Position",val:trainer.position||"—"},
    {lbl:"Employment",val:trainer.employment_status||"—"},
    {lbl:"State",val:trainer.state||"—"},
    {lbl:"TAE Credential",val:credCode},
    {lbl:"Questionnaire",val:`${qTot}/150 answered`},
    {lbl:"Experience",val:eTot>0?`${eApp}/${eTot} approved`:"Awaiting assignment"},
  ];
  sum.forEach((s,i)=>{
    const x=ML+i*(CW/sum.length);
    t(doc,s.lbl.toUpperCase(),x,57,5.5,C.light,true);
    t(doc,s.val,x,64,8.5,C.navy,true);
    if(i>0) ln(doc,x-1,50,x-1,67,C.grayBdr,0.2);
  });
  let y=76;

  // ── S1 ─────────────────────────────────────────────────────────────────────
  const s1st=trainerProfile?.s1_approved===true?"approved":trainerProfile?.s1_approved===false?"rejected":trainer?.full_name?"pending":null;
  y=secHead(doc,"Section 1 — Trainer Assessor Details",y,s1st);
  const fw=CW/3;
  [[["Full Name",trainer.full_name],["Email Address",trainer.email],["Phone",trainer.phone]],
   [["Position",trainer.position],["Employment Status",trainer.employment_status],["State",trainer.state]]
  ].forEach(row=>{
    row.forEach(([lbl,val],i)=>fldAt(doc,lbl,val,ML+i*fw,y,fw-4));
    y+=14;
  });
  y+=2; ln(doc,ML,y,ML+CW,y,C.grayBdr); y+=6;

  // ── S2 ─────────────────────────────────────────────────────────────────────
  y=chk(doc,y,45,drawFooter);
  const credst=trainerProfile?.profile_status==="Approved"?"approved":trainerProfile?.profile_status==="Rejected"?"rejected":(trainerProfile?.tae_qualification||trainerProfile?.under_direction_qualification)?"pending":null;
  y=secHead(doc,"Section 2 — Training and Assessment Credentials",y,credst);
  if(trainerProfile?.tae_qualification||trainerProfile?.under_direction_qualification){
    const isTAE=!!trainerProfile.tae_qualification;
    const qual=isTAE?trainerProfile.tae_qualification:trainerProfile.under_direction_qualification;
    const prov=isTAE?trainerProfile.tae_provider:trainerProfile.under_direction_provider;
    const provId=isTAE?trainerProfile.tae_provider_id:trainerProfile.under_direction_provider_id;
    const dateVal=isTAE?trainerProfile.tae_issue_date:trainerProfile.under_direction_commencement;
    const dateLbl=isTAE?"Issue Date":"Commencement";
    if(!isTAE){box(doc,ML,y,55,6,C.amberBg);t(doc,"UNDER DIRECTION",ML+2,y+4.5,6.5,C.amber,true);y+=8;}
    // Qualification full width row
    t(doc,"TAE QUALIFICATION",ML,y,5.5,C.light,true);
    const qLines=doc.splitTextToSize(qual||"—",CW*0.55);
    qLines.forEach((l,i)=>t(doc,l,ML,y+5+i*4.5,8,C.black));
    t(doc,"PROVIDER NAME",ML+CW*0.62,y,5.5,C.light,true);
    t(doc,prov||"—",ML+CW*0.62,y+5,8,C.black);
    y+=Math.max(5+qLines.length*4.5+3, 13);
    // Provider ID + date on second row
    fldAt(doc,"Provider ID",provId,ML,y,40);
    fldAt(doc,dateLbl,fmtDate(dateVal),ML+55,y,40);
    y+=13;
    const taeFiles=(evidenceFiles||[]).filter(f=>f.document_type==="TAE Credential"||f.document_type==="TAE Enrolment Evidence");
    if(taeFiles.length){
      t(doc,"UPLOADED EVIDENCE",ML,y,5.5,C.light,true);y+=5;
      taeFiles.forEach(f=>{
        y=chk(doc,y,8,drawFooter);
        box(doc,ML,y-3.5,CW,8,C.grayLt);
        t(doc,"[file]",ML+2,y+1.5,7.5,C.blue,true);
        t(doc,f.file_name,ML+15,y+1.5,8,C.mid);
        y+=9;
      });
    }
  } else {t(doc,"Not submitted",ML,y+5,8,C.light);y+=12;}
  ln(doc,ML,y,ML+CW,y,C.grayBdr);y+=6;

  // ── S3 ─────────────────────────────────────────────────────────────────────
  y=chk(doc,y,30,drawFooter);
  const qualst=trainerProfile?.industry_quals_approved===true?"approved":trainerProfile?.industry_quals_approved===false?"rejected":(industryQuals||[]).length>0?"pending":null;
  y=secHead(doc,"Section 3 — Industry Competencies",y,qualst);
  if(industryQuals&&industryQuals.length>0){
    box(doc,ML,y,CW,7,C.navy);
    const qcols=[{h:"Code",x:0,w:24},{h:"Title",x:25,w:62},{h:"Provider",x:88,w:42},{h:"Provider ID",x:131,w:26},{h:"Issue Date",x:158,w:24}];
    qcols.forEach(c=>t(doc,c.h.toUpperCase(),ML+c.x+1,y+5,5.5,C.white,true));
    y+=8;
    (industryQuals||[]).forEach((q,idx)=>{
      y=chk(doc,y,8,drawFooter);
      if(idx%2===0) box(doc,ML,y-1,CW,8,C.grayLt);
      t(doc,q.qualification_code||"—",ML+qcols[0].x+1,y+4.5,7,C.blue,true);
      t(doc,doc.splitTextToSize(q.qualification_title||"—",qcols[1].w)[0],ML+qcols[1].x+1,y+4.5,7,C.black);
      t(doc,doc.splitTextToSize(q.provider_name||"—",qcols[2].w)[0],ML+qcols[2].x+1,y+4.5,7,C.mid);
      t(doc,q.provider_id||"—",ML+qcols[3].x+1,y+4.5,7,C.mid);
      t(doc,fmtDate(q.issue_date),ML+qcols[4].x+1,y+4.5,7,C.mid);
      y+=8;
    });
    y+=2;
    const indFiles=(evidenceFiles||[]).filter(f=>f.document_type==="Industry Qualification");
    if(indFiles.length){
      t(doc,"CERTIFICATES UPLOADED",ML,y,5.5,C.light,true);y+=5;
      indFiles.forEach(f=>{
        y=chk(doc,y,8,drawFooter);
        box(doc,ML,y-3.5,CW,8,C.grayLt);
        t(doc,"[file]",ML+2,y+1.5,7.5,C.blue,true);
        t(doc,f.file_name,ML+15,y+1.5,8,C.mid);
        y+=9;
      });
    }
  } else {t(doc,"No industry qualifications submitted",ML,y+5,8,C.light);y+=12;}
  ln(doc,ML,y,ML+CW,y,C.grayBdr);y+=6;

  // ── S4 ─────────────────────────────────────────────────────────────────────
  y=chk(doc,y,28,drawFooter);
  const s4st=trainerProfile?.s4_approved===true?"approved":trainerProfile?.s4_approved===false?"rejected":trainerProfile?.declaration_signature?"pending":null;
  y=secHead(doc,"Section 4 — Credentials Declaration",y,s4st);
  [["Credentials Declared",trainerProfile?.declaration_credentials?"Confirmed":"Not confirmed"],
   ["Copies Provided",trainerProfile?.declaration_copies?"Confirmed":"Not confirmed"],
   ["Signature",trainerProfile?.declaration_signature],
   ["Declaration Date",fmtDate(trainerProfile?.declaration_date)]
  ].forEach(([lbl,val],i)=>fldAt(doc,lbl,val,ML+i*(CW/4),y,CW/4-4));
  y+=14; ln(doc,ML,y,ML+CW,y,C.grayBdr);y+=6;

  // ── S5 ─────────────────────────────────────────────────────────────────────
  y=chk(doc,y,55,drawFooter);
  y=secHead(doc,"Section 5 — Skills Questionnaire",y,(questResponses||[]).length===150?"approved":null);
  const qNo=(questResponses||[]).filter(r=>r.response==="no").length;
  const qHold=(questResponses||[]).filter(r=>r.response==="hold").length;
  const eRej=(experienceData||[]).filter(e=>e.competency_confirmed===false).length;
  const sc5=[
    {lbl:"Yes — Experience",val:qYes,bg:[219,234,254],fg:C.blue},
    {lbl:"No Experience",val:qNo,bg:C.grayLt,fg:C.gray},
    {lbl:"Hold",val:qHold,bg:C.amberBg,fg:C.amber},
    {lbl:"Total Answered",val:qTot,bg:C.purpBg,fg:C.purple},
    {lbl:"Units Approved",val:eApp,bg:C.greenBg,fg:C.green},
    {lbl:"Not Approved",val:eRej,bg:C.redBg,fg:C.red},
  ];
  const cw6=CW/6;
  sc5.forEach((c,i)=>{
    box(doc,ML+i*cw6,y,cw6-1,18,c.bg);
    t(doc,String(c.val),ML+i*cw6+cw6/2,y+11,15,c.fg,true,{align:"center"});
    t(doc,c.lbl,ML+i*cw6+cw6/2,y+17,5,C.light,false,{align:"center"});
  });
  y+=22;

  // Experienced streams callout
  if(streams&&streams.length>0){
    const expSt=streams.filter(s=>{
      const units=streamUnits[s.id]||[];
      if(!units.length) return false;
      return units.filter(u=>hasExp(questResponses,u)).length/units.length>=0.5;
    });
    if(expSt.length>0){
      y=chk(doc,y,16,drawFooter);
      box(doc,ML,y,CW,6,[219,234,254]);
      t(doc,"STREAMS WITH 50%+ TRAINER EXPERIENCE:",ML+2,y+4.5,6,C.blue,true);
      const names=expSt.map(s=>s.stream_name).join("   |   ");
      const nl=doc.splitTextToSize(names,CW-80);
      nl.forEach((l,i)=>t(doc,l,ML+74,y+4.5+i*5,6,C.navy));
      y+=6+Math.max(0,nl.length-1)*5+4;
    }
  }

  // Unit response grid — track page breaks properly
  t(doc,"UNIT RESPONSES  —  blue=experience   green=quality approved   red=not approved   amber=hold   grey=none",ML,y,5,C.light);
  y+=4;
  const gc=6, gw=CW/gc, gh=7.5;
  const sorted=[...(questResponses||[])].sort((a,b)=>a.unit_code.localeCompare(b.unit_code));
  // Render in rows, checking page break before each row
  for(let i=0;i<sorted.length;i+=gc){
    const rowUnits=sorted.slice(i,i+gc);
    y=chk(doc,y,gh,drawFooter);
    rowUnits.forEach((r,ci)=>{
      const exp=(experienceData||[]).find(e=>e.unit_code===r.unit_code);
      const isApp=r.response==="yes"&&exp?.competency_confirmed===true;
      const isRej=r.response==="yes"&&exp?.competency_confirmed===false;
      let cbg=C.grayLt,cfg=C.gray;
      if(isApp){cbg=[220,252,231];cfg=C.green;}
      else if(isRej){cbg=C.redBg;cfg=C.red;}
      else if(r.response==="yes"){cbg=[219,234,254];cfg=C.blue;}
      else if(r.response==="hold"){cbg=C.amberBg;cfg=C.amber;}
      box(doc,ML+ci*gw,y,gw-0.5,gh-0.5,cbg);
      t(doc,r.unit_code,ML+ci*gw+gw/2,y+5.2,5.8,cfg,true,{align:"center"});
    });
    y+=gh;
  }
  y+=4;

  // ── S6 ─────────────────────────────────────────────────────────────────────
  drawFooter(doc);
  doc.addPage();
  y=BTOP;
  const s6AllApp=eTot>0&&eApp===eTot;
  y=secHead(doc,"Section 6 — Industry Experience, Skills and Currency",y,s6AllApp?"approved":null);

  if(eTot===0){t(doc,"No units assigned yet",ML,y+5,8,C.light);y+=12;}
  else{
    const eNotApp=(experienceData||[]).filter(e=>e.competency_confirmed===false).length;
    const ePend=eTot-eApp-eNotApp;
    const eHolds=(experienceData||[]).filter(e=>e.holds_unit).length;
    const ec=[
      {lbl:"Approved",val:eApp,bg:C.greenBg,fg:C.green},
      {lbl:"Not Approved",val:eNotApp,bg:C.redBg,fg:C.red},
      {lbl:"Pending",val:ePend,bg:C.amberBg,fg:C.amber},
      {lbl:"Holds Unit",val:eHolds,bg:[219,234,254],fg:C.blue},
      {lbl:"Total Assigned",val:eTot,bg:C.grayLt,fg:C.navy},
    ];
    const ew=CW/ec.length;
    ec.forEach((c,i)=>{
      box(doc,ML+i*ew,y,ew-1,18,c.bg);
      t(doc,String(c.val),ML+i*ew+ew/2,y+11,15,c.fg,true,{align:"center"});
      t(doc,c.lbl,ML+i*ew+ew/2,y+17,5.5,C.light,false,{align:"center"});
    });
    y+=22;

    // Stream table — col layout: name | exp bar | appr bar | status
    if(streams&&streams.length>0){
      t(doc,"STREAM ASSIGNMENTS",ML,y,6,C.light,true);y+=5;
      // Column positions
      const SC={name:0,nameW:72,expLbl:73,barW:30,apprLbl:112,bar2W:30,status:150};
      // Header
      box(doc,ML,y,CW,6,C.navy);
      t(doc,"Stream",ML+SC.name+1,y+4.5,6,C.white,true);
      t(doc,"Trainer Experience",ML+SC.expLbl,y+4.5,6,C.white,true);
      t(doc,"Quality Approved",ML+SC.apprLbl,y+4.5,6,C.white,true);
      t(doc,"Status",ML+SC.status,y+4.5,6,C.white,true);
      y+=7;
      const grouped={};
      streams.forEach(s=>{
        if(!grouped[s.qualification_code]) grouped[s.qualification_code]=[];
        grouped[s.qualification_code].push(s);
      });
      Object.entries(grouped).forEach(([qual,qstreams])=>{
        y=chk(doc,y,9,drawFooter);
        box(doc,ML,y,CW,6.5,C.navyMid);
        t(doc,qual,ML+2,y+4.8,7.5,C.white,true);
        y+=7.5;
        qstreams.forEach(stream=>{
          y=chk(doc,y,7.5,drawFooter);
          const units=streamUnits[stream.id]||[];
          const appC=units.filter(u=>(experienceData||[]).find(e=>e.unit_code===u&&e.competency_confirmed===true)).length;
          const yesC=units.filter(u=>hasExp(questResponses,u)).length;
          const allA=units.length>0&&appC===units.length;
          const anyR=units.some(u=>(experienceData||[]).find(e=>e.unit_code===u&&e.competency_confirmed===false));
          const rowBg=allA?[240,253,244]:anyR?[254,234,234]:C.white;
          box(doc,ML,y-0.5,CW,7.5,rowBg);
          ln(doc,ML,y+7,ML+CW,y+7,C.grayBdr,0.15);
          // Name
          t(doc,stream.stream_name.slice(0,38),ML+SC.name+1,y+5,7,C.black);
          // Experience bar
          const ypct=units.length?yesC/units.length:0;
          box(doc,ML+SC.expLbl,y+2,SC.barW,3,C.grayBdr);
          if(ypct>0) box(doc,ML+SC.expLbl,y+2,SC.barW*ypct,3,C.teal);
          t(doc,`${yesC}/${units.length}`,ML+SC.expLbl+SC.barW+2,y+5,6,C.mid);
          // Approval bar
          const apct=units.length?appC/units.length:0;
          box(doc,ML+SC.apprLbl,y+2,SC.bar2W,3,C.grayBdr);
          if(apct>0) box(doc,ML+SC.apprLbl,y+2,SC.bar2W*apct,3,allA?C.green:C.teal);
          t(doc,`${appC}/${units.length}`,ML+SC.apprLbl+SC.bar2W+2,y+5,6,C.mid);
          // Status
          const stTxt=allA?"All Approved":anyR?"Some Not Approved":"In Progress";
          const stClr=allA?C.green:anyR?C.red:C.amber;
          t(doc,stTxt,ML+SC.status,y+5,6.5,stClr,allA||anyR);
          y+=7.5;
        });
        y+=2;
      });
      y+=4;
    }

    // Unit experience descriptions
    t(doc,"UNIT ASSESSMENTS  —  Trainer Experience Descriptions",ML,y,6,C.light,true);y+=5;
    const assignedCodes=(assignedUnits||[]).map(a=>a.unit_code).sort();
    assignedCodes.forEach((code)=>{
      const exp=(experienceData||[]).find(e=>e.unit_code===code);
      const unit=UNITS.find(u=>u.code===code);
      const statusTxt=exp?.competency_confirmed===true?"Approved":exp?.competency_confirmed===false?"Not Approved":"Pending";
      const statusClr=exp?.competency_confirmed===true?C.green:exp?.competency_confirmed===false?C.red:C.amber;
      const hBg=exp?.competency_confirmed===true?C.greenBg:exp?.competency_confirmed===false?C.redBg:C.grayLt;
      y=chk(doc,y,10,drawFooter);
      box(doc,ML,y,CW,8,hBg);
      t(doc,code,ML+2,y+5.5,7.5,C.blue,true);
      t(doc,(exp?.unit_title||unit?.title||code).slice(0,68),ML+24,y+5.5,7.5,C.black);
      t(doc,statusTxt,ML+CW-2,y+5.5,7,statusClr,true,{align:"right"});
      if(exp?.holds_unit) t(doc,"Holds unit",ML+CW-38,y+5.5,6,C.blue);
      y+=9;

      const descs=exp?.element_descriptions||{};
      const elements=unit?.elements||[];
      let hasContent=false;

      if(elements.length>0){
        elements.forEach((el,i)=>{
          const desc=descs[i]||descs[String(i)];
          if(!desc) return;
          hasContent=true;
          y=chk(doc,y,12,drawFooter);
          box(doc,ML+2,y,CW-2,5.5,[237,242,255]);
          t(doc,`${i+1}. ${el.slice(0,95)}`,ML+4,y+4,5.8,C.mid);
          y+=6;
          doc.splitTextToSize(desc,CW-10).forEach(l=>{
            y=chk(doc,y,5,drawFooter);
            t(doc,l,ML+4,y,7,C.black);
            y+=4.5;
          });
          y+=1;
        });
      } else {
        const desc=descs[0]||descs["0"]||exp?.professional_development;
        if(desc){
          hasContent=true;
          doc.splitTextToSize(desc,CW-8).forEach(l=>{
            y=chk(doc,y,5,drawFooter);
            t(doc,l,ML+4,y,7,C.black);
            y+=4.5;
          });
        }
      }
      if(exp?.professional_development&&elements.length>0){
        y=chk(doc,y,8,drawFooter);
        t(doc,"Professional Development / CPD:",ML+2,y,6,C.light,true);y+=4.5;
        doc.splitTextToSize(exp.professional_development,CW-8).forEach(l=>{
          y=chk(doc,y,5,drawFooter);
          t(doc,l,ML+4,y,7,C.mid);
          y+=4.5;
        });
      }
      if(!hasContent&&!exp?.professional_development){
        y=chk(doc,y,6,drawFooter);
        t(doc,"No experience descriptions recorded yet",ML+4,y,7,C.light);
        y+=6;
      }
      y+=3;
    });
  }

  // Final footer on every page
  const pc=doc.internal.getNumberOfPages();
  for(let i=1;i<=pc;i++){
    doc.setPage(i);
    box(doc,0,PH-FH,PW,FH,C.navy);
    t(doc,"Labtech Training  —  Trainer Competency Portal  —  Standards for RTOs 2025",ML,PH-3.5,6.5,[160,180,215]);
    t(doc,`Page ${i} of ${pc}`,PW-ML,PH-3.5,6.5,[160,180,215],false,{align:"right"});
  }

  const safe=(trainer.full_name||"trainer").replace(/[^a-zA-Z0-9]/g,"_");
  doc.save(`LTT_Competency_Profile_${safe}_${new Date().toISOString().slice(0,10)}.pdf`);
}